// AUTO-GENERATED. Base64-embedded fonts so the card SVG renders identically
// in the browser preview and in the canvas → PNG export, regardless of which
// fonts the host system has installed.
//
// Latin-subset woff2 from Google Fonts: Poppins (500, 700) for headings/labels,
// Roboto Mono (700) for numbers — matching the site's mono face.
export const FONT_STYLE = `<style>@font-face{font-family:'Poppins';font-style:normal;font-weight:500;font-display:block;src:url(data:font/woff2;base64,) format('woff2');}@font-face{font-family:'Poppins';font-style:normal;font-weight:700;font-display:block;src:url(data:font/woff2;base64,) format('woff2');}@font-face{font-family:'Roboto Mono';font-style:normal;font-weight:700;font-display:block;src:url(data:font/woff2;base64,) format('woff2');}</style>`
